SELECT /* @SQLID=SUB020301_01-03#Sql001 */ COUNT(*) OVER() AS totalCount, A.DATE_YMD AS dateYmd, A.BROKER_CODE AS brokerCode, A.BROKER_BRANCH_CODE AS brokerageBranchCode, A.BROKER_NAME AS brokerName, A.BROKER_CHARGE_CODE AS empCode, A.BROKER_CHARGE_NAME AS brokerChargeName, A.CUSTOMER_ATTRIBUTE_NAME AS courseName, A.BUTEN_CODE AS buten, A.ACCOUNT_NUMBER AS accountNumber, A.NAME_KANJI AS customerName, A.CURRENCY AS currency, A.FOREIGN_CURRENCT_PRICE AS foreignValuation, B.BRANCH_NAME AS brokerBranchName, C.NAME_KANA AS customerNameKana FROM V_BALANCE A LEFT JOIN MEDIATE_BRANCH B ON A.BROKER_CODE = B.BROKER_CODE AND A.BROKER_BRANCH_CODE = B.BROKER_BRANCH_CODE AND B.DELETE_FLG = '0' INNER JOIN MEDIATE_USER_ATTRIBUTE_INFO C ON A.BUTEN_CODE = C.BUTEN_CODE AND A.ACCOUNT_NUMBER = C.ACCOUNT_NUMBER WHERE A.DATE_YMD = #{req.dateYmd} AND A.PRODUT_CD = '98' AND A.FOREIGN_CURRENCT_PRICE < 0
AND(A.BROKER_CODE IN
) OR A.BROKER_CODE IN(
,
#{brokerCharge.brokerCode}
)
AND ((A.BROKER_CODE, A.BROKER_CHARGE_CODE) IN
) OR (A.BROKER_CODE, A.BROKER_CHARGE_CODE) IN(
,
(#{brokerCharge.brokerCode}, #{brokerCharge.empCode})
)
AND A.BROKER_CODE IN
#{brokerCode}
AND A.BROKER_CODE NOT IN
#{brokerCode}
AND A.BROKER_BRANCH_CODE = #{req.branchCode}
AND A.BROKER_CHARGE_CODE = #{req.empCode}
AND A.BUTEN_CODE = #{req.butenCode}
AND A.ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})
AND (C.NAME_KANJI = #{req.customerNameKanjiKana} OR C.NAME_KANA = #{req.customerNameKanjiKana})
AND (C.NAME_KANJI LIKE CONCAT(#{req.customerNameKanjiKana},'%') OR C.NAME_KANA like CONCAT(#{req.customerNameKanjiKana},'%'))
AND (C.NAME_KANJI LIKE CONCAT(CONCAT('%',#{req.customerNameKanjiKana}),'%') OR C.NAME_KANA like CONCAT(CONCAT('%',#{req.customerNameKanjiKana}),'%'))
AND A.CUSTOMER_ATTRIBUTE IN
#{course}
ORDER BY A.BROKER_CODE, A.BROKER_CHARGE_CODE, A.BUTEN_CODE, A.ACCOUNT_NUMBER, A.CURRENCY FETCH FIRST 5000 ROWS ONLY
